import { isEmptyObject, mergeJSON } from '../../../../utils/zcutils';
import { getHighlightElement, highlightLI, highlightLabel, highlightMarker, getListIndex } from './highlight-item-helpers';
import { getHoverOptions } from '../../legend-event-helpers';

export function HighlightItem(mouse, data) {
    let manager = this,
        { options } = manager,
        { trackerElement, config, globalFont, boxSize } = options,
        { ranges } = config,
        hoverOptions = getHoverOptions(config),
        point = getListIndex(data, options),
        highlightElement = getHighlightElement(trackerElement, point);

    if (isEmptyObject(hoverOptions)) {
        return;
    }

    if (ranges && ranges[data.point].disabled) {
        return;
    }

    let markerConfig = config.list.marker,
        labelConfig = hoverOptions.label,
        hoverMarkerConfig = hoverOptions.marker,
        mergedHoverMarkerConfig = isEmptyObject(hoverMarkerConfig) ? hoverMarkerConfig : mergeJSON(hoverMarkerConfig, markerConfig),
        //
        labelElement = highlightElement.selectAll('.zc-legend-legendlabel, .zc-legend-legendlabel *'),
        markerElement = highlightElement.selectAll('.zc-legend-legendfilterbox');

    highlightLI(highlightElement, hoverOptions);
    highlightLabel(labelElement, config, globalFont, labelConfig);
    highlightMarker(markerElement, boxSize, markerConfig, mergedHoverMarkerConfig);
}
